// ─── CONFIGURACIÓN ──────────────────────────────────────────────────
// Edita aquí los grupos de destinatarios, los umbrales y las secciones
// que se vigilan. NO toca el código posterior — todo se lee de aquí.

const cfg = {
  // Proyecto Asana de Integraciones
  asana_project_id: '1207920061546505',

  // Días sin avance que disparan la alerta (created_at o última actividad).
  // 7 = una semana sin movimiento.
  umbral_dias: 7,

  // Secciones que SÍ vigilamos (las demás no generan recordatorio).
  // Estas suelen ser las de "esperando al cliente".
  secciones_seguimiento: [
    'Solicitud de datos realizada',
    'Datos incorrectos y notificados',
    'Integraciones pendientes'
  ],

  // Grupos de notificación. Cada grupo recibe SU email con SUS tareas.
  // - destinatarios: lista separada por comas (n8n SMTP lo acepta así).
  // - filtro_tpv: si está vacío [], se incluyen todos los TPVs;
  //   si tiene valores, sólo se envían esas integraciones a este grupo.
  // - filtro_secciones: igual, vacío = todas las de seguimiento.
  grupos: [
    {
      nombre: 'Equipo Integraciones',
      destinatarios: 'soporte@yurest.com,a.jareno@yurest.com',
      filtro_tpv: [],
      filtro_secciones: []
    }
    // Ejemplo de grupo extra:
    // {
    //   nombre: 'Equipo Comercial - TPV Lastapp',
    //   destinatarios: 'comercial@yurest.com',
    //   filtro_tpv: ['Lastapp'],
    //   filtro_secciones: []
    // }
  ]
};

return [{ json: cfg }];

// Filtra tareas "sin avance": no completadas, en una sección de seguimiento
// del proyecto Integraciones, y con created_at/modified_at más antiguo que
// el umbral configurado. Devuelve UN ITEM POR TAREA para que el siguiente
// HTTP Request (stories) se ejecute por cada una.
const cfg = $('Configuración').first().json;
const data = $input.first().json;
const tasks = Array.isArray(data) ? data : (data.data || data.tasks || []);

const seccionesSet = new Set(cfg.secciones_seguimiento);
const projectId    = String(cfg.asana_project_id);
const umbralMs     = (cfg.umbral_dias || 7) * 24 * 60 * 60 * 1000;
const ahora        = Date.now();

// Devuelve el nombre de la sección que la tarea tiene DENTRO de nuestro
// proyecto (las tareas pueden estar en varios proyectos a la vez).
function seccionEnProyecto(t) {
  const ms = Array.isArray(t.memberships) ? t.memberships : [];
  const own = ms.find(m => m && m.project && String(m.project.gid) === projectId);
  if (own && own.section && own.section.name) return own.section.name;
  return null;
}

function getTPV(t) {
  const cfs = Array.isArray(t.custom_fields) ? t.custom_fields : [];
  const c = cfs.find(x => (x && x.name && x.name.toLowerCase().trim() === 'tpv'));
  if (!c) return '';
  return c.display_value
      || (c.enum_value && c.enum_value.name)
      || c.text_value
      || '';
}

function diasDesde(iso) {
  if (!iso) return null;
  const t = new Date(iso).getTime();
  if (isNaN(t)) return null;
  return Math.floor((ahora - t) / (24*60*60*1000));
}

const stale = [];
for (const t of tasks) {
  if (!t || t.completed) continue;
  const sec = seccionEnProyecto(t);
  if (!sec || !seccionesSet.has(sec)) continue;

  // El umbral compara contra `modified_at` si existe (más cercano a la
  // realidad de "avance"), si no, contra `created_at`.
  const refIso = t.modified_at || t.created_at;
  const ref    = refIso ? new Date(refIso).getTime() : 0;
  if (!ref || (ahora - ref) < umbralMs) continue;

  stale.push({
    json: {
      gid: t.gid,
      nombre: t.name || '(Sin nombre)',
      seccion: sec,
      tpv: getTPV(t) || 'Sin TPV',
      asignado: (t.assignee && t.assignee.name) || '',
      permalink: t.permalink_url || '',
      created_at: t.created_at,
      modified_at: t.modified_at,
      dias_creada: diasDesde(t.created_at),
      dias_inactiva: diasDesde(refIso)
    }
  });
}

return stale;

// Empareja por índice cada respuesta de stories con la tarea
// correspondiente (n8n preserva el orden cuando un HTTP Request se
// ejecuta por item). Adjunta a cada tarea su último comentario real
// (resource_subtype='comment_added'), descartando eventos del sistema.
const tareas     = $('Filtrar tareas sin avance').all();
const respuestas = $input.all();

function extraerUltimoComentario(resp) {
  if (!resp || !resp.json) return null;
  const data = resp.json.data || resp.json || [];
  const comments = (Array.isArray(data) ? data : [])
      .filter(s => s && s.resource_subtype === 'comment_added')
      // Asana devuelve cronológicamente; nos quedamos con el último.
      .sort((a, b) => String(a.created_at || '').localeCompare(String(b.created_at || '')));
  const last = comments.length ? comments[comments.length - 1] : null;
  if (!last) return null;
  return {
    autor: (last.created_by && last.created_by.name) || '—',
    fecha: last.created_at || '',
    texto: (last.text || '').trim()
  };
}

const out = tareas.map((t, i) => ({
  json: {
    ...t.json,
    ultimoComentario: extraerUltimoComentario(respuestas[i])
  }
}));

return out;

// Agrupa tareas por destinatarios (cfg.grupos) y compone UN ITEM POR
// EMAIL a enviar. Si un grupo no tiene tareas que matcheen su filtro,
// no se genera item (no se envía email vacío).
const cfg     = $('Configuración').first().json;
const tareas  = $input.all().map(i => i.json);
const result  = [];

const esc = s => String(s == null ? '' : s)
  .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');

const fmtFecha = iso => {
  if (!iso) return '—';
  const d = new Date(iso);
  if (isNaN(d.getTime())) return String(iso);
  return d.toLocaleDateString('es-ES', { day:'2-digit', month:'short', year:'numeric' });
};

const fechaEnvio = new Date().toLocaleDateString('es-ES', { day:'2-digit', month:'long', year:'numeric' });

for (const grupo of (cfg.grupos || [])) {
  let lista = [...tareas];

  if (grupo.filtro_tpv && grupo.filtro_tpv.length) {
    const set = new Set(grupo.filtro_tpv);
    lista = lista.filter(t => set.has(t.tpv));
  }
  if (grupo.filtro_secciones && grupo.filtro_secciones.length) {
    const set = new Set(grupo.filtro_secciones);
    lista = lista.filter(t => set.has(t.seccion));
  }

  if (lista.length === 0) continue;

  // Más antiguas primero (más urgentes).
  lista.sort((a, b) => (b.dias_inactiva || 0) - (a.dias_inactiva || 0));

  const filas = lista.map(t => {
    const c = t.ultimoComentario;
    const cmtBlock = c
      ? `<div style="margin-top:8px;padding:10px 12px;background:#f8fafc;border-left:3px solid #cbd5e1;border-radius:0 8px 8px 0;font-size:12px;color:#475569;line-height:1.5">
            <div style="font-weight:700;color:#1e293b;margin-bottom:4px">${esc(c.autor)} · <span style="color:#94a3b8;font-weight:500">${esc(fmtFecha(c.fecha))}</span></div>
            <div style="white-space:pre-wrap">${esc(c.texto).replace(/\n/g,'<br>')}</div>
          </div>`
      : `<div style="margin-top:8px;padding:10px 12px;background:#fef9c3;border-left:3px solid #facc15;border-radius:0 8px 8px 0;font-size:12px;color:#854d0e">
            Sin comentarios todavía en la tarea.
          </div>`;

    const tagDias = `<span style="display:inline-block;padding:2px 8px;border-radius:999px;background:#fee2e2;color:#b91c1c;font-size:11px;font-weight:700;margin-left:6px">${t.dias_inactiva || t.dias_creada} días</span>`;

    return `
      <tr><td style="padding:14px 18px;border-bottom:1px solid #f1f5f9">
        <div>
          <a href="${esc(t.permalink)}" target="_blank" style="color:#fc5858;font-weight:700;text-decoration:none;font-size:14px">${esc(t.nombre)}</a>
          ${tagDias}
        </div>
        <div style="font-size:11px;color:#64748b;margin-top:3px">
          <strong>${esc(t.tpv)}</strong> · ${esc(t.seccion)}${t.asignado ? ' · ' + esc(t.asignado) : ''}
        </div>
        ${cmtBlock}
      </td></tr>`;
  }).join('');

  const total = lista.length;
  const subject = `Yurest · ${total} integració${total !== 1 ? 'n pendientes' : 'n pendiente'} sin avance · ${grupo.nombre}`;

  const html = `<!DOCTYPE html>
<html lang="es">
<body style="margin:0;padding:0;background:#f1f5f9;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif">
<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#f1f5f9;padding:32px 16px">
  <tr><td align="center">
    <table width="100%" cellpadding="0" cellspacing="0" border="0" style="max-width:680px">
      <tr><td style="background:linear-gradient(135deg,#0f172a,#3a0f0f);border-radius:14px 14px 0 0;padding:26px 32px">
        <p style="margin:0;font-size:11px;font-weight:700;letter-spacing:.14em;text-transform:uppercase;color:#fca5a5">Yurest · Integraciones</p>
        <p style="margin:8px 0 0;font-size:20px;font-weight:700;color:#fff">${total} cliente${total !== 1 ? 's' : ''} sin contestar</p>
        <p style="margin:6px 0 0;font-size:12px;color:#cbd5e1">${esc(grupo.nombre)} · resumen del ${esc(fechaEnvio)}</p>
      </td></tr>
      <tr><td style="background:#fff;padding:20px 28px;font-size:13px;color:#334155;line-height:1.55;border-bottom:1.5px solid #f1f5f9">
        Las siguientes tareas llevan más de <strong>${cfg.umbral_dias} días</strong> en una sección de seguimiento sin movimiento. A continuación se incluye el último comentario registrado en Asana, para que sirva de contexto al retomar el contacto con el cliente.
      </td></tr>
      <tr><td style="background:#fff">
        <table width="100%" cellpadding="0" cellspacing="0" border="0">${filas}</table>
      </td></tr>
      <tr><td style="background:#f8fafc;border-radius:0 0 14px 14px;border-top:1.5px solid #e2e8f0;padding:14px 32px;font-size:11px;color:#94a3b8">
        © Yurest · Aviso semanal automático generado desde el panel de Integraciones
      </td></tr>
    </table>
  </td></tr>
</table>
</body>
</html>`;

  result.push({
    json: {
      destinatarios: grupo.destinatarios,
      grupo: grupo.nombre,
      subject,
      html,
      total
    }
  });
}

return result;
